import { CountryInfo, SafetyLevel, VisaCategory } from "@/types";
import { PriceTier, TIER_PRICE } from "./priceTiers";

// v1: 東南アジア〜南アジア以外の国を一括投入するための簡易データ。
// 精度は今後の定期更新で高めていく前提(設計書12章「手動キュレーション+定期更新」)。
interface CountrySeed {
  code: string;
  code2: string;
  nameJa: string;
  nameEn: string;
  capital: string;
  timezone: string;
  plugType: string;
  language: string;
  safetyLevel: SafetyLevel;
  tier: PriceTier;
  visaForJapanese: VisaCategory;
  maxStayDays: number;
  visaNote: string;
  currencyCode: string;
  currencySymbol: string;
  police: string;
  ambulance: string;
  tippingCustom?: boolean;
  tippingNote?: string;
}

function build(s: CountrySeed): CountryInfo {
  const p = TIER_PRICE[s.tier];
  return {
    code: s.code,
    code2: s.code2,
    nameJa: s.nameJa,
    nameEn: s.nameEn,
    capital: s.capital,
    timezone: s.timezone,
    plugType: s.plugType,
    language: s.language,
    safetyLevel: s.safetyLevel,
    costIndex: p.costIndex,
    priceSenseJPY: { hotel: p.hotel, food: p.food, sightseeing: p.sightseeing },
    visaForJapanese: s.visaForJapanese,
    visaDetail: {
      maxStayDays: s.maxStayDays,
      // ビザ不要の国は「ビザなし◯◯日以内」に表記を統一する
      notes: s.visaForJapanese === "unnecessary" ? `ビザなし${s.maxStayDays}日以内` : s.visaNote,
    },
    currency: { code: s.currencyCode, symbol: s.currencySymbol },
    emergency: {
      police: s.police,
      ambulance: s.ambulance,
      embassyJa: { address: "要確認(外務省 在外公館リストを参照)", phone: "要確認" },
    },
    sim: { availability: "情報未整備", avgPriceUSD: 10, esimSupport: false },
    wifi: { avgSpeedNote: "情報未整備", availability: "情報未整備" },
    phrases: [],
    tipping: { custom: s.tippingCustom ?? false, note: s.tippingNote ?? "情報未整備" },
    lastUpdated: "2026-07-14",
  };
}

